public class SelectionSort {

    public static void sort(int[] arr) {
        int n = arr.length;

        for (int i = 0; i < n - 1; i++) {
            int minIdx = i;                     // assume current is minimum

            // Find the actual minimum in unsorted portion [i+1 .. n-1]
            for (int j = i + 1; j < n; j++) {
                if (arr[j] < arr[minIdx]) {
                    minIdx = j;
                }
            }

            // Swap minimum into correct position (only if needed)
            if (minIdx != i) {
                int temp      = arr[i];
                arr[i]        = arr[minIdx];
                arr[minIdx]   = temp;
            }
        }
    }

    public static void main(String[] args) {
        int[] arr = {64, 25, 12, 22, 11};
        sort(arr);
        System.out.println(Arrays.toString(arr)); // [11, 12, 22, 25, 64]
    }
}

public class InsertionSort {

    public static void sort(int[] arr) {
        int n = arr.length;

        for (int i = 1; i < n; i++) {
            int key = arr[i]; // element to insert
            int j   = i - 1;

            // Shift elements of arr[0..i-1] that are > key one position right
            while (j >= 0 && arr[j] > key) {
                arr[j + 1] = arr[j];
                j--;
            }

            arr[j + 1] = key; // insert key in its correct position
        }
    }

    // Binary insertion sort — uses binary search to find insert position
    // Reduces comparisons to O(n log n) but shifts are still O(n²)
    public static void binaryInsertionSort(int[] arr) {
        for (int i = 1; i < arr.length; i++) {
            int key = arr[i];
            int pos = Arrays.binarySearch(arr, 0, i, key);
            if (pos < 0) pos = -(pos + 1);
            System.arraycopy(arr, pos, arr, pos + 1, i - pos);
            arr[pos] = key;
        }
    }

    public static void main(String[] args) {
        int[] arr = {12, 11, 13, 5, 6};
        sort(arr);
        System.out.println(Arrays.toString(arr)); // [5, 6, 11, 12, 13]
    }
}

public class HeapSort {

    public static void sort(int[] arr) {
        int n = arr.length;

        // Phase 1: Build max-heap
        // Start from last non-leaf: index n/2 - 1, go backwards to root
        for (int i = n / 2 - 1; i >= 0; i--) {
            heapify(arr, n, i);
        }

        // Phase 2: Extract elements from heap one by one
        for (int i = n - 1; i > 0; i--) {
            // Move current root (max) to end
            int temp = arr[0];
            arr[0]   = arr[i];
            arr[i]   = temp;

            // Heapify the reduced heap (size = i, root = 0)
            heapify(arr, i, 0);
        }
    }

    /**
     * Heapify subtree rooted at index i, with heap size n.
     * Ensures arr[i] >= its children (max-heap property).
     */
    private static void heapify(int[] arr, int n, int i) {
        int largest = i;         // assume root is largest
        int left    = 2 * i + 1; // left child index
        int right   = 2 * i + 2; // right child index

        if (left  < n && arr[left]  > arr[largest]) largest = left;
        if (right < n && arr[right] > arr[largest]) largest = right;

        if (largest != i) {      // root isn't largest — swap and recurse
            int temp      = arr[i];
            arr[i]        = arr[largest];
            arr[largest]  = temp;
            heapify(arr, n, largest); // fix the subtree we just disrupted
        }
    }

    public static void main(String[] args) {
        int[] arr = {12, 11, 13, 5, 6, 7};
        sort(arr);
        System.out.println(Arrays.toString(arr)); // [5, 6, 7, 11, 12, 13]
    }
}

public class CountingSort {

    public static void sort(int[] arr) {
        if (arr.length == 0) return;

        // Find the range
        int max = arr[0];
        for (int v : arr) max = Math.max(max, v);

        // Count occurrences
        int[] count = new int[max + 1];
        for (int v : arr) count[v]++;

        // Prefix sum — count[i] now = number of elements <= i
        for (int i = 1; i <= max; i++) {
            count[i] += count[i - 1];
        }

        // Build output array (right-to-left for stability)
        int[] output = new int[arr.length];
        for (int i = arr.length - 1; i >= 0; i--) {
            output[count[arr[i]] - 1] = arr[i];
            count[arr[i]]--;
        }

        // Copy back
        System.arraycopy(output, 0, arr, 0, arr.length);
    }

    // Simple version (not stable) — just reconstruct from counts
    public static void sortSimple(int[] arr) {
        int max = 0;
        for (int v : arr) max = Math.max(max, v);
        int[] count = new int[max + 1];
        for (int v : arr) count[v]++;
        int idx = 0;
        for (int v = 0; v <= max; v++)
            while (count[v]-- > 0) arr[idx++] = v;
    }

    public static void main(String[] args) {
        int[] arr = {4, 2, 2, 8, 3, 3, 1};
        sort(arr);
        System.out.println(Arrays.toString(arr)); // [1, 2, 2, 3, 3, 4, 8]
    }
}

public class RadixSort {

    public static void sort(int[] arr) {
        if (arr.length == 0) return;
        int max = arr[0];
        for (int v : arr) max = Math.max(max, v);

        // Sort by each digit position (1s, 10s, 100s, ...)
        for (int exp = 1; max / exp > 0; exp *= 10) {
            countingSortByDigit(arr, exp);
        }
    }

    // Stable counting sort on digit = (arr[i] / exp) % 10
    private static void countingSortByDigit(int[] arr, int exp) {
        int n = arr.length;
        int[] output = new int[n];
        int[] count  = new int[10]; // digits 0-9

        // Count occurrences of each digit
        for (int v : arr) count[(v / exp) % 10]++;

        // Prefix sum
        for (int i = 1; i < 10; i++) count[i] += count[i - 1];

        // Build output (right-to-left for stability)
        for (int i = n - 1; i >= 0; i--) {
            int digit = (arr[i] / exp) % 10;
            output[count[digit] - 1] = arr[i];
            count[digit]--;
        }

        System.arraycopy(output, 0, arr, 0, n);
    }

    public static void main(String[] args) {
        int[] arr = {170, 45, 75, 90, 802, 24, 2, 66};
        sort(arr);
        System.out.println(Arrays.toString(arr)); // [2, 24, 45, 66, 75, 90, 170, 802]
    }
}

public class BucketSort {

    // Sort array of floats in [0, 1)
    public static void sortFloats(float[] arr) {
        int n = arr.length;
        if (n <= 1) return;

        // Create n empty buckets
        List<Float>[] buckets = new ArrayList[n];
        for (int i = 0; i < n; i++) buckets[i] = new ArrayList<>();

        // Distribute elements into buckets
        for (float v : arr) {
            int idx = (int)(v * n); // maps [0,1) to [0,n)
            if (idx == n) idx--;    // handle v = 1.0 edge case
            buckets[idx].add(v);
        }

        // Sort each bucket and concatenate
        int pos = 0;
        for (List<Float> bucket : buckets) {
            Collections.sort(bucket); // insertion sort under the hood for small lists
            for (float v : bucket) arr[pos++] = v;
        }
    }

    // Sort integers in range [0, maxVal]
    public static void sortIntegers(int[] arr, int maxVal) {
        int n = arr.length;
        List<Integer>[] buckets = new ArrayList[n];
        for (int i = 0; i < n; i++) buckets[i] = new ArrayList<>();

        for (int v : arr) {
            int idx = (int)((long) v * (n - 1) / maxVal);
            buckets[idx].add(v);
        }

        int pos = 0;
        for (List<Integer> bucket : buckets) {
            Collections.sort(bucket);
            for (int v : bucket) arr[pos++] = v;
        }
    }

    public static void main(String[] args) {
        float[] arr = {0.78f, 0.17f, 0.39f, 0.26f, 0.72f, 0.94f, 0.21f};
        sortFloats(arr);
        System.out.println(Arrays.toString(arr));
    }
}
